const qwen = async (messages, model, opts = {}) => {
  const base = ($env.DASHSCOPE_BASE_URL || 'https://dashscope-intl.aliyuncs.com/compatible-mode/v1').replace(/\/$/, '');
  const res = await this.helpers.httpRequest({
    method: 'POST', url: base + '/chat/completions',
    headers: { Authorization: 'Bearer ' + ($env.DASHSCOPE_API_KEY || ''), 'Content-Type': 'application/json' },
    body: Object.assign({ model, temperature: 0, messages }, opts), json: true,
  });
  return res.choices?.[0]?.message?.content ?? '';
};
const esc = (s) => String(s).replace(/'/g, "''");
const rows = $input.all().map(i => i.json);
const events = rows.slice(0, 120).map(r =>
  `- [${r.event_type}] ${r.agent_id}: ${(r.title || '').toString()} ${(r.event_text || '').toString().slice(0, 160)}`
).join('\n');
const sys = "You are The Showrunner. Turn the agent society's day into a short, vivid recap episode in markdown: a '# title', 3-5 beat bullets, and a one-line teaser. Under 200 words. Invent nothing not in the events.";
const out = await qwen(
  [{ role: 'system', content: sys }, { role: 'user', content: 'Events (last 24h):\n' + (events || '(a quiet day — note it briefly)') }],
  ($env.QWEN_CHAT_MODEL || 'qwen-plus'), {});
const title = (out.match(/^#\s*(.+)$/m)?.[1] || 'Daily recap').slice(0, 120);
return [{ json: { recap_md: esc(out), episode_title: esc(title), event_count: rows.length } }];
